{
  "verses": [
    {
      "n": 2,
      "column": "left",
      "text": "Isglahb manni mans\nDreews no manneem Eenaiduce-\nkeem/ patwerr mannis no teem/\nkas prett manni zelkahs.\n"
    },
    {
      "n": 3,
      "column": "left",
      "text": "Isglahb mann no teem\nLaunadarritajeem / un atpesti\nmann no teem Affinn Landin.\n"
    },
    {
      "n": 4,
      "column": "left",
      "text": "Jo rangi/ tee gluhte us\nmannu Dwehfeli / tee Stipree\nfapulzejahs prett mannis man-\nnas Wainas/ un bes manneem\nGrehkeem af KUNGS!\n"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Tee tekk un taitahs bes\nmannas Noseegschanas/ usmoh-\nstajs man pretti/ un redsi.\n"
    },
    {
      "n": 6,
      "column": "left",
      "text": "Tu ak KUNGS Deews\nZebaits! Israëta Deews/ ns-\nmobstajs peemekeleht wiffus Pa-\nganus/ ne apschehlojees pahr ne\nweenu/ kas tik wiltigi us Netaif-\nnibu dohdahs/ Sela.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Wakkarâ lai tee atkatkanz\nka Sunni/ un eeksch Pilsfahta\napkahrt teffa.\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Redsi/ tee ar fatwu Mutti\nplukfschke/ Sobbinii irr eeksch wik-\nna Luhpahn/ jo kas to klausa:\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "Bet tu KUNGS pahr\nteen fineetees/ tu apmehdift wif-\nfus Paganus.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Prett winno Warru es\nus tewi qaadischu/ jo Deews irr\nmans Patwerums.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Deews parahda man fa-\nwu Schehlastibu baggatigi/\nDeews leek man fatwus Pretti-\nnekus (ar Preeku) usluhkoht.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Ne nokaujitohs/ ka man-\n"
    },
    {
      "n": 13,
      "column": "right",
      "text": "(Par) teem Grehkee\nwinnu Muttes/ un (par)\nWahrdü winno Luhpu : Lai\nfaguhstiti tohp eeksch Jawas Le\nnibas/ tik labbi winnu Lah\nschanas/ ka Mellu pehz/ ko\nisteiz.\n"
    },
    {
      "n": 14,
      "column": "right",
      "text": "Isdelde tohs eeksch D\nmibas/ isDelde tohs/ ka tee\nneneeku tohp/un atsibst ka Dee\npar Walditaju irr eeksch Jeh\nba/ liths Bafantes Galleer\nSela.\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Lai tee Wakkarâ at\nkanz ka tee Sunni / un eet\nPilsfahta apkahrt teffa.\n"
    },
    {
      "n": 16,
      "column": "right",
      "text": "Lai tee tchurp un t\nskaida Barribas pehz/ un kur\nkad tee ne pee-ehd.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Bet es dseedatchu no\nwa! Stipruma/ un teikschu D\ntos tawn Schehlastibu/ jo tu\nman par augstu Patwerumm\njis/ un par Gelbeschannu\nDeena/ kad man bail bija.\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "No tervis dseedaschu\nmans Stiprums/ jo tu Dee\neffi mans Patwerums/ me\nschehligajs Deews.\n"
    }
  ],
  "confidence": "high",
